class GeometryCommandError(Exception):
    def __init__(self,msg):
        self.msg = msg
    def __str__(self):
        return str(self.msg)

class Geometry(object):
    def __init__(self,a=1,b=1,c=1,h=1,r=1,d=2,R=2,C=None,S=None,V=None,l=5,angle=360):
        self.a = a
        self.b = b
        self.c = c
        self.h = h
        self.r = r
        self.d = d
        self.R = R
        self.C = C
        self.S = S
        self.V = V
        self.l = l
        self.angle = angle

    # жӯЈж–№еҪў
    def square(self,question='S'):
        if question == 'C' or question == 'е‘Ёй•ҝ':
            return ['Cв–Ў=4a',str(self.a)+'*4',self.a*4]
        elif question == 'S' or question == 'йқўз§Ҝ':
            return ['Sв–Ў=aВІ',str(self.a)+'^2',self.a**2]
        else:
            raise GeometryCommandError('[Error_01]еҮ дҪ•е‘Ҫд»ӨиҜӯжі•ж— ж•Ҳ')

    # й•ҝж–№еҪў
    def rectangle(self,question='S'):
        if question == 'C' or question == 'е‘Ёй•ҝ':
            return ['Cв–ғ =2(a+b)','('+str(self.a)+'+'+str(self.b)+')*2',(self.a+self.b)*2]
        elif question == 'S' or question == 'йқўз§Ҝ':
            return ['Sв–ғ =ab',str(self.a)+'*'+str(self.b),self.a*self.b]
        else:
            raise GeometryCommandError('[Error_01]еҮ дҪ•е‘Ҫд»ӨиҜӯжі•ж— ж•Ҳ')

    # е№іиЎҢеӣӣиҫ№еҪў
    def parallelogram(self,question='S'):
        if question == 'C' or question == 'е‘Ёй•ҝ':
            return ['Cв–ұ =2(a+b)','('+str(self.a)+'+'+str(self.b)+')*2',(self.a+self.b)*2]
        elif question == 'S' or question == 'йқўз§Ҝ':
            return ['Sв–ұ =ah',str(self.a)+'*'+str(self.h),self.a*self.h]
        else:
            raise GeometryCommandError('[Error_01]еҮ дҪ•е‘Ҫд»ӨиҜӯжі•ж— ж•Ҳ')

    # дёүи§’еҪў
    def triangle(self,question='S'):
        if question == 'C' or question == 'е‘Ёй•ҝ':
            return ['Cв–і =a+b+c',str(self.a)+'+'+str(self.b)+'+'+str(self.c),self.a+self.b+self.c]
        elif question == 'S' or question == 'йқўз§Ҝ':
            return ['Sв–і =ah/2',str(self.a)+'*'+str(self.h)+'/2',self.a*self.h/2]
        else:
            raise GeometryCommandError('[Error_01]еҮ дҪ•е‘Ҫд»ӨиҜӯжі•ж— ж•Ҳ')

    # жўҜеҪў
    def trapezium(self,question='S'):
        if question == 'C' or question == 'е‘Ёй•ҝ':
            return ['CжўҜ=a+b+c+h',str(self.a)+'+'+str(self.b)+'+'+str(self.c)+'+'+str(self.h),self.a+self.b+self.c+self.h]
        elif question == 'S' or question == 'йқўз§Ҝ':
            return ['SжўҜ=(a+b)h/2','('+str(self.a)+'+'+str(self.b)+')*'+str(self.h)+'/2',(self.a+self.b)*self.h/2]
        else:
            raise GeometryCommandError('[Error_01]еҮ дҪ•е‘Ҫд»ӨиҜӯжі•ж— ж•Ҳ')

    # еңҶ
    def circle(self,question='S',know='r'):
        if question == 'C' or question == 'е‘Ёй•ҝ':
            if know == 'r':
                return ['Cв—Ӣ=2ПҖr','2ПҖ*'+str(self.r),str(self.r*2)+'ПҖ']
            else:
                return ['Cв—Ӣ=ПҖd','ПҖ*'+str(self.d),str(self.d)+'ПҖ']
        elif question == 'S' or question == 'йқўз§Ҝ':
            if know == 'r':
                return ['Sв—Ӣ=ПҖrВІ','ПҖ*'+str(self.r)+'ВІ',str(self.r**2)+'ПҖ']
            else:
                return ['Sв—Ӣ=ПҖ(d/2)ВІ','ПҖ*('+str(self.d)+'/2)ВІ',str((self.d/2)**2)+'ПҖ']
        else:
            raise GeometryCommandError('[Error_01]еҮ дҪ•е‘Ҫд»ӨиҜӯжі•ж— ж•Ҳ')

    # зҺҜ
    def ring(self):
        return ['Sв—Һ=ПҖ(RВІ-rВІ)','ПҖ*('+str(self.R)+'ВІ-'+str(self.r)+'ВІ)',str(self.R**2-self.r**2)+'ПҖ']

    # жӨӯеңҶ
    def ellipse(self,question='S'):
        if question == 'L' or question == 'е‘Ёй•ҝ':
            return ['LжӨӯ=2ПҖb+4(a-b)','2ПҖ*'+str(self.b)+'+4*('+str(self.a)+'-'+str(self.b)+')',str(self.b*2)+'ПҖ+'+str((self.a-self.b)*4)]
        elif question == 'S' or question == 'йқўз§Ҝ':
            return ['SжӨӯ=ПҖab','ПҖ*'+str(self.a)+'*'+str(self.b),str(self.a*self.b)+'ПҖ']
        else:
            raise GeometryCommandError('[Error_01]еҮ дҪ•е‘Ҫд»ӨиҜӯжі•ж— ж•Ҳ')


